INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Floating face bubbles$q$, $q$Each participant appears as a small round video window that can be dragged anywhere on screen, instead of a full rectangular call window.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$AI auto-framing$q$, $q$An AI camera system automatically keeps each person's face centered and in focus within their bubble, acting like an automatic camera operator.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$EchoPrevention$q$, $q$Ultrasonic audio detects nearby open microphones in the same room and suppresses feedback, so hybrid teammates can sit together without headphones.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Noise cancellation$q$, $q$AI-based audio filtering removes background sounds like barking dogs, sirens, and traffic during calls.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Reactions, filters, and icebreakers$q$, $q$Emoji reactions, camera filters, and icebreaker sounds add lightweight, informal touches to everyday calls.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Ambient vibes and mini-games$q$, $q$Optional background music and simple multiplayer games designed for casual hangouts rather than agenda-driven meetings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Screen sharing$q$, $q$Standard screen sharing that kept participants' face bubbles visible on top of shared content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Recording$q$, $q$A recording feature (introduced in beta in 2022) let teams capture calls for later reference.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Cross-platform apps$q$, $q$Native apps for Mac, Windows, and the web, plus iOS and Android mobile apps launched in mid-2021.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Miro board integration$q$, $q$After the 2022 acquisition, calls could be launched and joined directly from a Miro whiteboard.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Distinctive floating-bubble format reduced the fatigue of staring at a grid of video tiles all day$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$AI face-framing kept presenters visible and well-composed without manual webcam adjustments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$EchoPrevention solved the common problem of audio feedback when several people share a room$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Lightweight, always-on feel encouraged spontaneous, hallway-style conversations for remote teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Simple, playful interface with reactions, filters, and icebreakers that lowered the barrier to informal check-ins$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Discontinued on March 31, 2025 — no longer available as a standalone product to sign up for$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Capped participant counts made it unsuitable for large all-hands meetings or webinars$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$No phone dial-in or PSTN support for participants without a computer or app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Recording and admin/compliance controls were limited compared with mainstream platforms like Zoom or Teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Best features (like EchoPrevention) depended on decent hardware and microphone quality to work well$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Is Around still available today?$q$, $q$No. Around was sunset on March 31, 2025. Miro, which acquired the company in October 2022, retired the standalone app and folded features like floating mode, reactions, and EchoPrevention into its own Video Calls product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Who acquired Around, and when?$q$, $q$Miro, the visual-collaboration platform, acquired Around in October 2022. The deal terms were not publicly disclosed, and the product was rebranded as Around by Miro Labs before eventually being discontinued.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$What made Around's interface different from Zoom or Google Meet?$q$, $q$Instead of a rectangular grid of video tiles, Around showed each participant as a small floating circle that could be moved around the screen and left open while multitasking in other apps.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Can I still get Around's features somewhere else?$q$, $q$Many of Around's signature features, including floating mode, reactions, filters, EchoPrevention, and recording, were rebuilt directly into Miro's own Video Calls product before Around was sunset.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$What platforms did Around support?$q$, $q$Around offered native apps for Mac, Windows, and the web, plus iOS and Android mobile apps that launched in mid-2021.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Remote pair programming and co-working$q$, $q$Engineers kept a persistent Around bubble open for hours to collaborate on code and ask quick questions without scheduling a formal call.$q$, $q$Distributed software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Ambient virtual office presence$q$, $q$Hybrid and remote-first teams used Around as a lightweight, always-on way to feel co-located and available for spontaneous chats.$q$, $q$Hybrid and remote-first companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Creative collaboration alongside a whiteboard$q$, $q$After the Miro acquisition, design and product teams launched Around calls directly from a Miro board to pair video with visual brainstorming.$q$, $q$Design and product teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Quick standups and 1:1 check-ins$q$, $q$Small startup teams used Around's low-friction bubbles for brief daily standups and one-on-ones without a full-screen meeting interrupting their workflow.$q$, $q$Distributed startup teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Free$q$, $q$$0$q$, NULL, $q$["Floating-bubble video calls","AI auto-framing","EchoPrevention","Reactions, filters, and icebreakers","Screen sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$Pro (historical, pre-acquisition)$q$, $q$Not publicly disclosed$q$, $q$monthly$q$, $q$["Higher participant limits","Additional team/admin controls","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Around was a lightweight video calling app that reimagined what a call could look like: instead of a full-screen grid of rectangular tiles, participants appeared as small floating circles that could be dragged anywhere on screen and left running while people worked in other apps. Co-founded in 2018 by Dominik Zane and Pavel Serbajlo, with Matt Zakutny, the company spent nearly two years in stealth before launching publicly in March 2020, just as the pandemic pushed remote and hybrid work into the mainstream. Around went on to raise more than 15 million dollars in funding from investors including Floodgate, Initialized Capital, Credo Ventures, and the Slack Fund, and grew to a team of roughly three dozen people.$q$, $q$The company's central bet was that most video-calling fatigue came from the format, not the underlying technology: staring at a grid of faces all day is exhausting, and closing a call to focus on other work can feel isolating for a distributed team. Around's floating bubbles, AI-driven face framing, and ultrasonic EchoPrevention technology were built to let people keep a call open in the background, more like sitting near a coworker than attending a formal meeting. In October 2022, Around was acquired by the visual-collaboration platform Miro, with deal terms not publicly disclosed, and rebranded as Around by Miro Labs. Miro kept the product free for all users while folding its best ideas into its own video tools, and ultimately discontinued the standalone Around app on March 31, 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$who-around-is-for$q$, $q$Who Around Is For$q$, 2, ARRAY[$q$Around was built for distributed and hybrid teams who wanted a call to feel like being in the next room rather than attending a scheduled meeting. Pair-programming duos, co-working friends, and small startup teams used it to keep a lightweight video connection open for hours at a time, popping in and out of conversation the way colleagues would in a shared physical office rather than dialing in and out of formal blocks on a calendar.$q$, $q$It also suited creative and product teams who valued the playful, informal touches layered on top of a genuinely useful AI camera and audio system, things like reactions, camera filters, icebreaker sounds, and small multiplayer games that made spontaneous check-ins feel less like work. After the Miro acquisition, it was a natural fit for teams already using Miro's whiteboard for brainstorming and workshops, since it let them add a synchronous video layer without ever leaving the collaborative canvas they were already working in.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$The most important consideration today is that Around no longer exists as a product anyone can buy or adopt: it was sunset on March 31, 2025, and its accounts, recordings, and third-party integrations were shut down along with it. Anyone evaluating video-calling tools now should look at Miro's built-in Video Calls, which absorbed features like EchoPrevention, reactions, filters, and floating mode, or at mainstream alternatives such as Zoom, Google Meet, or Microsoft Teams.$q$, $q$Even when it was active, Around was a poor fit for large or formal meetings. It intentionally capped participant counts, offered no dial-in or PSTN support, had limited recording and admin controls compared with mainstream platforms, and lacked the compliance and enterprise-management features that larger organizations expect. Companies running large all-hands calls, webinars, sales demos, or anything requiring phone-based access generally chose a heavier-duty platform instead, even during Around's most popular years.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Around's signature feature was its floating circular video windows: instead of a rectangular call window competing for screen space, each participant appeared as a small round bubble that could be dragged anywhere on the desktop and stayed visible while using other apps. An AI auto-framing system kept each person's face centered and in focus inside that circle, effectively acting as an automatic camera operator so nobody had to think about their webcam position.$q$, $q$On the audio side, Around's EchoPrevention used ultrasonic tones to detect nearby open microphones and automatically suppress feedback loops, a common pain point when several hybrid teammates sat in the same conference room without headphones. It paired this with noise cancellation that filtered out barking dogs, sirens, and other background sound, and it shipped with lightweight social extras: emoji reactions, camera filters, icebreaker sounds, ambient background music dubbed vibes, and simple multiplayer games meant for informal hangouts rather than agenda-driven meetings.$q$, $q$Around also supported screen sharing, added a beta recording feature in 2022, and offered native apps across Mac, Windows, the web, iOS, and Android, with the mobile apps arriving in mid-2021. After Miro's acquisition, it gained the ability to launch and join calls directly from a Miro board, bringing video and visual whiteboard collaboration into a single window instead of two separate tools.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb2d22a1-1ce3-4203-a28c-4dcd411456cf', $q$the-around-experience$q$, $q$The Around Experience$q$, 2, ARRAY[$q$Day to day, using Around felt closer to leaving a door open than scheduling a meeting: teammates joined a persistent room, their face bubbles appeared floating over whatever else was on screen, and conversations could start and stop organically, much like a hallway chat in a physical office rather than a calendar-blocked call. That ambient, always-on quality, combined with a genuinely useful camera and audio experience, is what earned Around a loyal following among early remote-work adopters and a wave of enthusiastic press coverage in 2020 and 2021.$q$, $q$Under Miro's ownership, Around remained free for all users while its team worked on integrating the product with Miro's canvas. By 2024, Miro had built a very similar experience, floating mode, reactions, filters, EchoPrevention, and recording, directly into its own Video Calls product, and it retired the standalone Around app on March 31, 2025. For anyone who misses the format, Around's core ideas now live on inside Miro rather than as an independent product people can sign up for today.$q$]::text[], 4);
