INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Offer Management & Approvals$q$, $q$Configurable offer-approval workflows and offer-letter generation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$AI Meeting Notetaker$q$, $q$Records interviews and generates automatic summaries for hiring teams (paid add-on).$q$, 7);
