INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Pricing is based on total company headcount, which can rise as a company grows headcount even without more hiring$q$, 1);
