INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Configuration flexibility can create a learning curve for new admins$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Does Ashby offer a free trial?$q$, $q$No. Ashby does not offer a self-serve free trial or free plan; prospective customers evaluate the platform through a sales demo and proof-of-concept process.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$How much does Ashby cost?$q$, $q$Ashby's Foundations plan starts at roughly $400 per month for companies with up to 100 employees, with a discount for annual billing. Pricing for larger companies (101-1,000+ employees) is custom-quoted based on total headcount.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$What is Ashby used for?$q$, $q$Ashby is used as an all-in-one recruiting platform, combining applicant tracking, candidate sourcing and CRM, interview scheduling automation, and hiring analytics in a single system.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Who founded Ashby and when?$q$, $q$Ashby was founded in 2018 by Benjamin Encz and Abhik Pramanik and is headquartered in San Francisco, California.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Does Ashby integrate with other HR and recruiting tools?$q$, $q$Yes. Ashby offers integrations with job boards, assessment providers, calendars, and HRIS platforms, plus an open API and webhooks for custom connections.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Scaling startup hiring$q$, $q$Replacing spreadsheets or a legacy ATS with a single unified system as hiring volume grows.$q$, $q$Talent acquisition teams at venture-backed startups (Series A-C)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Data-driven recruiting operations$q$, $q$Standing up built-in funnel, source, and interviewer-load analytics without exporting data to a separate BI tool.$q$, $q$Recruiting operations and people-analytics leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Technical and engineering hiring$q$, $q$Running structured interview kits, scorecards, and technical assessment integrations for engineering-heavy hiring.$q$, $q$Engineering recruiting and technical talent teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Migrating off a legacy ATS$q$, $q$Moving from an older ATS like Greenhouse or Lever to a more modern interface with native reporting.$q$, $q$Talent leaders evaluating an ATS switch$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Foundations$q$, $q$From $400/month$q$, $q$monthly$q$, $q$["For companies up to 100 employees","Core ATS, CRM, scheduling, and analytics","Careers page builder","Capped email/sourcing lookups"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$All-In-One Plus$q$, $q$Custom quote$q$, $q$annual$q$, $q$["For companies with 101-1,000 employees","Full recruiting platform feature set","Expanded usage limits","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual$q$, $q$["For companies with 1,000+ employees","Advanced security and admin controls","Dedicated account management","Custom integration support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ashby is a modern applicant tracking system (ATS) and recruiting platform built for high-growth technology companies. Founded in 2018 by Benjamin Encz and Abhik Pramanik and based in San Francisco, Ashby set out to replace the fragmented stack of legacy ATS tools, spreadsheets, and point solutions that many recruiting teams cobble together, with a single unified product spanning sourcing, applicant tracking, interview scheduling, and reporting.$q$, $q$Unlike many older-generation ATS platforms, Ashby was built with analytics as a first-class feature rather than an afterthought, giving talent teams pipeline, funnel-conversion, and recruiter-productivity dashboards natively instead of relying on third-party BI exports. The platform also bundles a sourcing CRM and outbound email/sequencing tools, letting recruiters build and nurture candidate pipelines without leaving the product.$q$, $q$Ashby has grown into one of the more widely adopted ATS options among venture-backed startups and scale-ups, and has layered in AI-assisted features over time, including automatic interview note-taking and summaries and AI-assisted candidate sourcing, while keeping its configurable interview and hiring-process engine as the backbone of the product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$who-ashby-is-for$q$, $q$Who Ashby Is For$q$, 2, ARRAY[$q$Ashby is aimed squarely at in-house talent acquisition teams at venture-backed startups and scale-ups, roughly Series A through pre-IPO, that are hiring at volume and need a single system of record for the entire funnel. Companies that have outgrown Greenhouse, Lever, or a spreadsheet-based process, and want a more modern interface plus built-in reporting, tend to be a strong fit.$q$, $q$It particularly suits recruiting leaders who care about hiring analytics — time-to-hire, source performance, interviewer load, funnel conversion — and don't want to stitch that data together manually. Technical and engineering-heavy hiring organizations also benefit from Ashby's structured interview kits, scorecards, and assessment integrations.$q$, $q$Because pricing is based on total company headcount and contracts are typically annual, Ashby tends to work best for organizations with a dedicated recruiting or People Ops function that can own the system, rather than a single hiring manager making occasional ad hoc hires.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small companies, solo founders, or teams making only a handful of hires a year will likely find Ashby's pricing and annual-contract model heavier than necessary. There is no free plan or free trial, so lightweight or occasional hiring needs are often better served by simpler, cheaper ATS tools.$q$, $q$Large, non-tech enterprises with complex multi-country HR/compliance requirements or deep legacy HRIS and payroll integration needs may find that more established enterprise ATS/HCM suites offer more mature compliance tooling out of the box.$q$, $q$Teams that want to try before they buy should also weigh the lack of a self-serve trial: evaluating Ashby means going through a sales demo and proof-of-concept rather than signing up independently, which can be friction for smaller or more DIY-oriented teams.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Ashby offers a configurable applicant tracking system with customizable pipelines, interview stages, and hiring-process automation, alongside a sourcing CRM for building talent pools, running email outreach sequences, and tracking passive-candidate engagement over time.$q$, $q$Scheduling automation handles interview-panel coordination across calendars and time zones, while the analytics layer provides dashboards on pipeline health, funnel conversion, source effectiveness, and interviewer activity that can be sliced by requisition, department, or recruiter. Ashby also includes a careers-page builder, offer-approval workflows, and an open API and webhooks that connect to job boards, assessment providers, calendars, and HRIS platforms.$q$, $q$More recently, Ashby has added AI-driven features, including an AI meeting notetaker that records and summarizes interviews and AI-assisted tools for surfacing and filtering candidates, layered on top of the same structured-interview and scorecard framework that anchors the hiring process.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', $q$the-ashby-experience$q$, $q$The Ashby Experience$q$, 2, ARRAY[$q$Day to day, recruiters and hiring managers generally describe Ashby's interface as fast, clean, and noticeably more modern than legacy ATS tools, with less clicking required to move candidates through a pipeline or pull a report. The reporting experience is frequently cited as a differentiator versus competitors that require exporting data to third-party BI tools.$q$, $q$Onboarding typically involves a guided setup with Ashby's team to configure interview processes, permissions, and integrations, and the vendor is known for being responsive to customer feedback and shipping frequent product updates. Support and account management are generally rated well by customers, particularly during initial rollout.$q$, $q$Tradeoffs some teams report include a learning curve around the platform's flexibility, since there are many ways to configure a hiring process, add-on pricing for features like advanced scheduling or the AI notetaker, and the commitment of an annual contract without a self-serve trial to test fit beforehand.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6a6164-cd5b-4456-afd7-cd85def0c06a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
