INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Patient portal & athenaPatient app$q$, $q$Separate patient-facing portal and mobile app for viewing records, messaging providers, and managing appointments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Population health & quality reporting$q$, $q$Tools to support value-based care initiatives and quality programs such as MIPS reporting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Interoperability & health information exchange$q$, $q$Connections for exchanging clinical data with other providers, labs, and health systems.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Analytics & reporting dashboards$q$, $q$Operational and financial dashboards giving practice leadership visibility into performance metrics.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Deep revenue-cycle and billing expertise, with a centrally maintained payer rules engine intended to reduce claim denials$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Cloud delivery means athenahealth handles hosting, maintenance, and regulatory rule updates, lowering internal IT burden$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2debbb6c-85ad-4634-b256-8049d7c1bd11', $q$Broad specialty coverage and scalability, from solo practices to large multi-specialty and multi-location groups$q$, 2);
