INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa65c3e9-f1eb-4bc3-88cc-e1c6bbc4e49a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Common Data Environment (Autodesk Docs)$q$, $q$Centralized, version-controlled storage for drawings, models, and project documents with markups and transmittal tracking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Field Management (Autodesk Build)$q$, $q$RFIs, submittals, daily logs, punch lists, and quality/safety checklists for on-site construction teams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Cost Management$q$, $q$Model-based quantity takeoff linked to budgets, change orders, and payment applications, built on the former Assemble Systems technology.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Model Coordination (BIM Collaborate Pro)$q$, $q$Cloud-based clash detection and multi-discipline model review for design and coordination teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Takeoff$q$, $q$2D and 3D quantity takeoff tools that pull directly from linked Autodesk models.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Bid Management (BuildingConnected)$q$, $q$Subcontractor prequalification and bid solicitation network for preconstruction teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Insight Dashboards$q$, $q$Portfolio-level analytics and reporting that aggregate data across projects for executives and owners.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Mobile Field Apps$q$, $q$Native iOS and Android apps with offline access to drawings and forms, syncing when reconnected.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$API / Autodesk Platform Services$q$, $q$Developer APIs for custom integrations, data extraction, and connections to third-party or ERP systems.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$AI-Assisted Workflows$q$, $q$AI capabilities that help automate data extraction and analysis from drawings, specifications, and project data.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Deep, native integration with Autodesk design tools like Revit, AutoCAD, and Civil 3D keeps model and field data connected.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Broad module coverage spans design coordination, document control, field management, cost management, and bidding in one ecosystem.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Mobile apps offer reliable offline access to large drawing sets, a strength inherited from PlanGrid.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Portfolio-level reporting via Insight gives owners and executives visibility across multiple projects.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Backed by Autodesk's scale, meaning ongoing investment, a large partner network, and established enterprise support.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Pricing is not published and requires a sales conversation, making cost comparisons harder than with self-serve competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$The multi-module structure (Docs, Build, Cost Management, Takeoff, BIM Collaborate) can create a learning curve around which module does what.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Value is strongest for teams already using Autodesk design software; non-BIM users may not need its full feature set.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Rollout across a construction organization can require dedicated admin/IT resources to configure permissions and workflows.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$As a suite consolidated from several acquisitions, some legacy workflows and interfaces feel less unified than a platform built from a single codebase.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Is Autodesk Construction Cloud the same as BIM 360?$q$, $q$BIM 360 was Autodesk's earlier cloud collaboration platform. Autodesk Construction Cloud is the successor umbrella that incorporates BIM 360's capabilities alongside PlanGrid, Assemble Systems, and BuildingConnected into a broader connected suite.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$How much does Autodesk Construction Cloud cost?$q$, $q$Autodesk does not publish standard per-seat pricing for Construction Cloud. Costs depend on which modules (Docs, Build, Cost Management, Takeoff, BIM Collaborate) and license quantities are selected, and are quoted directly through Autodesk sales or a reseller.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Does Autodesk Construction Cloud integrate with Revit and AutoCAD?$q$, $q$Yes. As an Autodesk product, ACC is designed to connect directly with Revit, AutoCAD, and Civil 3D, allowing models and drawings to flow into document management, coordination, and field workflows.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Is there a free trial available?$q$, $q$Autodesk has offered free trials for Construction Cloud products in the past; availability and specific terms should be confirmed on the current construction.autodesk.com site, since trial offerings can change.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$What happened to PlanGrid?$q$, $q$PlanGrid, a field document management app Autodesk acquired in 2018, was integrated into Autodesk Construction Cloud and its capabilities now live primarily within Autodesk Build and Autodesk Docs.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Field Management for General Contractors$q$, $q$Track RFIs, submittals, daily logs, and quality/safety inspections from the job site, with mobile offline access for crews.$q$, $q$General contractors and construction managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Portfolio Oversight for Owners$q$, $q$Aggregate project data across a capital program into portfolio-level dashboards for reporting and decision-making.$q$, $q$Owners and capital program managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$BIM Coordination for Design-Build Teams$q$, $q$Run multi-discipline clash detection and model review to keep design and construction teams aligned before issues reach the field.$q$, $q$Design-build firms and BIM coordinators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Quantity Takeoff and Cost Management for Estimators$q$, $q$Derive quantities directly from linked 3D models and connect them to budgets, change orders, and payment applications.$q$, $q$Estimators and cost management teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Autodesk Docs$q$, $q$Custom pricing (contact sales)$q$, $q$annual$q$, $q$["Common data environment for drawings and documents","Version control and markups","Transmittals and approval workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Autodesk Build$q$, $q$Custom pricing (contact sales)$q$, $q$annual$q$, $q$["RFIs and submittals","Daily logs and punch lists","Quality and safety checklists","Mobile field app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Autodesk BIM Collaborate Pro$q$, $q$Custom pricing (contact sales)$q$, $q$annual$q$, $q$["Cloud-based model coordination","Multi-discipline clash detection","Design review and markup"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$Autodesk Cost Management$q$, $q$Custom pricing (contact sales)$q$, $q$annual$q$, $q$["Model-based quantity takeoff","Budget and change order tracking","Payment application management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Autodesk Construction Cloud (ACC) is Autodesk's unified construction management platform, built to connect design, preconstruction, and field operations around a single common data environment. Rather than being built from scratch, ACC was assembled by folding together several products Autodesk acquired over the years — BIM 360, its original cloud collaboration platform; PlanGrid, a widely used field document and drawing management tool; Assemble Systems, a model-based quantification and cost management engine; and BuildingConnected, a bid management network — into one connected suite.$q$, $q$Today, ACC acts as the umbrella for Autodesk's construction-facing cloud products, sitting alongside BIM Collaborate (Autodesk's design coordination tool) within the broader Autodesk AEC (architecture, engineering, construction) ecosystem. It handles document control, RFIs, submittals, quality and safety inspections, punch lists, model coordination, cost management, and reporting, and it ties directly into Autodesk's design authoring tools such as Revit, AutoCAD, and Civil 3D.$q$, $q$Because of that lineage, ACC's core differentiator is depth of BIM integration: it's built to keep a project's 3D model, 2D drawings, and field data in sync, which positions it against competitors like Procore, Oracle Aconex, and Trimble/Viewpoint as the option most tightly coupled to Autodesk's design software stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$who-its-for$q$, $q$Who Autodesk Construction Cloud Is For$q$, 2, ARRAY[$q$ACC is aimed at general contractors, construction managers, and owners running capital construction programs who need a single system of record across design, preconstruction, and field execution. It's particularly well suited to teams already working inside the Autodesk ecosystem — firms using Revit, AutoCAD, or Civil 3D for design who want that model data to flow directly into field workflows without re-uploading or reformatting files.$q$, $q$Design-build firms, large subcontractors coordinating trades on BIM-heavy projects, and owners who need visibility across a portfolio of projects also get strong value from ACC's reporting and Insight dashboards. Because pricing and rollout are handled through Autodesk's enterprise sales process, it tends to suit organizations with the internal resources — an IT/BIM manager, a construction technology lead — to manage implementation, permissions, and training across multiple project teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small contractors, solo builders, or residential remodelers looking for a lightweight, self-serve tool for basic scheduling or photo documentation will likely find ACC heavier and more expensive than they need. Its value is closely tied to BIM workflows, so teams that don't design in Autodesk software (or don't work with 3D models at all) lose a significant part of what differentiates ACC from simpler field-management apps.$q$, $q$Organizations that want transparent, published per-seat pricing and an instant online checkout should also be cautious — Autodesk sells ACC through a quote-based, sales-assisted process, and comparing costs against competitors requires a direct conversation rather than a pricing page. Teams without dedicated technical support to handle permissions, module configuration, and change management across a construction organization may find the rollout more demanding than expected.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Autodesk Docs provides the common data environment: version-controlled drawing and document management, markups, and file transmittals that every other ACC module builds on. Autodesk Build layers in day-to-day field management — RFIs, submittals, daily logs, punch lists, quality and safety checklists, and issue tracking — while Autodesk Cost Management (built on the former Assemble Systems technology) connects model-derived quantities to budgets, change orders, and payment applications.$q$, $q$For design and model coordination, Autodesk BIM Collaborate Pro enables multi-discipline clash detection and cloud-based model review, and Autodesk Takeoff supports 2D and 3D quantity takeoff directly from linked models. BuildingConnected extends the platform upstream into bid management and subcontractor prequalification, while Autodesk Insight aggregates project data into portfolio-level dashboards and reporting for executives and owners.$q$, $q$Native mobile apps for iOS and Android let field crews access drawings, log issues, and complete inspections offline, syncing once connectivity returns, and Autodesk Platform Services (formerly Forge) exposes APIs for custom integrations, data extraction, and connecting ACC to other construction or ERP systems.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', $q$the-experience$q$, $q$The Autodesk Construction Cloud Experience$q$, 2, ARRAY[$q$Day to day, ACC feels like a suite of purpose-built modules stitched together rather than one monolithic app — a byproduct of its acquisition-driven history. Users generally find the individual tools (Docs, Build, Takeoff) capable and well-designed on their own, but the overall breadth means new teams face a real learning curve around permissions, module selection, and how data flows between design and field.$q$, $q$Autodesk has invested in unifying account administration, single sign-on, and shared project data across modules, and has been layering in AI-assisted capabilities — such as automated data extraction from drawings and specifications — to reduce manual setup work. Mobile performance in the field is generally regarded as a strength, a legacy of PlanGrid's original focus on reliable offline access to large drawing sets.$q$, $q$Support and training are delivered through Autodesk's enterprise channels, including a certified partner network, documentation, and Autodesk University resources, which suits larger organizations more than teams expecting lightweight, self-service onboarding.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9aff19f-2369-4d96-b80f-e33c932398f4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
