INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Drag-and-drop email builder$q$, $q$Design newsletters and campaigns visually using a library of customizable templates without needing HTML or design experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Automation (Campaigns)$q$, $q$Build tag- and behavior-based automated sequences that trigger emails when subscribers join a list, click a link, or take other actions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Landing pages$q$, $q$Create standalone landing pages to capture leads or promote offers, integrated directly with AWeber's email lists and forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Sign-up forms and pop-ups$q$, $q$Embed customizable opt-in forms and pop-ups on websites or blogs to grow an email list.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$AI writing assistance$q$, $q$Generate email copy, subject lines, and content suggestions with built-in AI tools to speed up campaign creation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$RSS-to-email automation$q$, $q$Automatically convert new blog posts into email newsletters using RSS feed triggers, useful for bloggers and publishers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$E-commerce integrations$q$, $q$Connect with payment and store platforms such as PayPal, Stripe, and Etsy to sell products and trigger purchase-based emails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Reporting and analytics$q$, $q$Track opens, clicks, and campaign performance through a built-in analytics dashboard.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Third-party integrations$q$, $q$Connect AWeber to hundreds of other tools and apps, including website builders, CRMs, and e-commerce platforms, natively or via Zapier.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Customer support$q$, $q$Access live phone support, chat, and email assistance, a differentiator versus many competitors that offer only chat or tickets.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Genuine free plan available for small subscriber lists$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Live phone support, uncommon among email marketing competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Long operating history and reputation for reliability and deliverability$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Beginner-friendly interface with a strong template library$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Combines email, landing pages, and forms in a single platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Interface feels more traditional and less modern than some newer competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Automation builder is less flexible than platforms like ActiveCampaign$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Pricing increases as subscriber lists grow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Limited advanced CRM and lead-scoring capabilities$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$E-commerce automation is less deep than dedicated platforms like Klaviyo$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Does AWeber have a free plan?$q$, $q$Yes, AWeber offers a free plan for small subscriber lists with limited features, making it accessible for people just starting with email marketing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Is AWeber good for beginners?$q$, $q$Yes, AWeber is widely considered beginner-friendly thanks to its drag-and-drop builder, pre-built templates, and straightforward automation setup.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Does AWeber integrate with WordPress and Shopify?$q$, $q$AWeber offers integrations with popular platforms including WordPress and various e-commerce tools, either natively or through services like Zapier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Does AWeber offer phone support?$q$, $q$Yes, AWeber provides live phone support in addition to chat and email, which is uncommon among email marketing providers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Can I migrate my email list from another provider to AWeber?$q$, $q$Yes, AWeber supports importing subscriber lists from other email platforms, and its support team can assist with migration.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Solo bloggers and newsletter writers$q$, $q$Send regular newsletters and automatically convert new blog posts into emails using RSS-to-email automation.$q$, $q$Independent bloggers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Small business promotions$q$, $q$Build and send promotional campaigns and manage customer lists without a dedicated marketing team.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Course creators and coaches$q$, $q$Set up automated onboarding and nurture sequences for students or clients using tag-based triggers.$q$, $q$Coaches, consultants, and online course creators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Local business and e-commerce broadcasts$q$, $q$Send announcement and promotional broadcasts tied to payment integrations like PayPal or Etsy.$q$, $q$Local businesses and small online sellers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Up to 500 subscribers","1 email list","Limited templates","AWeber branding on emails"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Lite$q$, $q$From ~$12.50/month$q$, $q$annual$q$, $q$["Unlimited automation","Unlimited landing pages","No AWeber branding","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Plus$q$, $q$From ~$20/month$q$, $q$annual$q$, $q$["Advanced automation and segmentation","Multiple team users","Additional integrations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$Unlimited$q$, $q$Custom / contact sales$q$, NULL, $q$["Designed for very large subscriber lists (100,000+)","Dedicated account support","Custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$AWeber is one of the oldest email service providers still operating today, founded in 1998 by Tom Kulzer and headquartered in Chalfont, Pennsylvania. It predates most of the modern email marketing category and has spent over two decades building tools specifically for small businesses, bloggers, and solo entrepreneurs rather than large enterprise marketing teams.$q$, $q$At its core, AWeber is an email marketing and automation platform: it lets users build newsletters and drip campaigns, create landing pages and sign-up forms, and automate follow-up sequences based on subscriber behavior and tags. In recent years the company has layered in AI-assisted content tools, such as writing prompts and subject line suggestions, to speed up campaign creation for non-technical users.$q$, $q$AWeber has positioned itself around ease of use, deliverability, and a long-standing reputation for responsive customer support, including live phone assistance, which is unusual in a category where most competitors offer only chat or ticket-based help.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$who-aweber-is-for$q$, $q$Who AWeber Is For$q$, 2, ARRAY[$q$AWeber is best suited to solopreneurs, bloggers, coaches, authors, and small local businesses that need a straightforward way to grow an email list and send regular newsletters or promotional campaigns without a steep learning curve.$q$, $q$It also appeals to creators who want an all-in-one starter toolkit: a single platform that combines email sending, basic landing pages, and sign-up forms without having to stitch together several separate tools. Its free plan makes it a reasonable entry point for people testing email marketing for the first time on a very small list.$q$, $q$Users who value phone-based customer support, and who prioritize a stable, long-established provider over the newest feature set, also tend to gravitate toward AWeber.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger e-commerce brands that need deep behavioral segmentation, advanced revenue attribution, or tightly built Shopify/WooCommerce automation flows are typically better served by e-commerce-first platforms such as Klaviyo, which offer more granular purchase-based triggers.$q$, $q$Teams that want a combined email and sales CRM with complex, branching multi-step automation, lead scoring, and pipeline management may find AWeber's automation builder comparatively basic compared to tools like ActiveCampaign or HubSpot.$q$, $q$Fast-growing companies with very large or rapidly scaling subscriber lists should also compare total cost carefully, since AWeber's pricing rises with list size and some larger-list tiers require contacting sales rather than self-service checkout.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$AWeber's core toolkit centers on a drag-and-drop email builder with a library of pre-built templates, paired with tag-based automation ('Campaigns') that lets users trigger sequences based on subscriber actions like sign-ups, link clicks, or purchases.$q$, $q$Beyond email, the platform includes a landing page builder, customizable sign-up forms and pop-ups, and RSS-to-email automation for bloggers who want new posts automatically converted into newsletters. AI-assisted writing and subject-line tools have been added to help users draft content faster.$q$, $q$AWeber also supports e-commerce and payment integrations (including PayPal, Stripe, and Etsy), a broad library of third-party integrations, basic analytics and reporting, and a mobile app for managing campaigns on the go.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', $q$the-aweber-experience$q$, $q$The AWeber Experience$q$, 2, ARRAY[$q$Day-to-day, AWeber feels geared toward simplicity: the dashboard, list management, and campaign builder are designed so non-technical users can get a newsletter or automated sequence live within an afternoon, without needing design or coding skills.$q$, $q$The interface has a more traditional, form-driven feel compared to some newer, highly visual competitors, which some long-time users find reassuring and others find dated. Template and automation flexibility, while solid for standard use cases, is less extensive than what more automation-heavy platforms offer.$q$, $q$Where AWeber consistently differentiates itself is support: live phone support, chat, and email assistance are all available, and the company has built its reputation over decades on being responsive when customers run into setup or deliverability questions.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
