INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a33e3f3c-6c06-46f7-81a5-f47a7ab9dc18', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Elastic Compute (EC2)$q$, $q$Resizable virtual servers across dozens of instance families, letting teams match compute, memory, and GPU capacity to any workload.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Serverless Computing (Lambda)$q$, $q$Run code in response to events without provisioning or managing servers, paying only for compute time actually used.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Managed Databases$q$, $q$Amazon RDS, Aurora, and DynamoDB handle provisioning, patching, backups, and replication for relational and NoSQL workloads.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Global Networking & Delivery$q$, $q$Amazon VPC, Route 53, and CloudFront provide private networking, DNS, and low-latency content delivery worldwide.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Identity & Access Management (IAM)$q$, $q$Granular permissions and role-based access control for users, applications, and services across an AWS account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$AI & Machine Learning$q$, $q$Amazon SageMaker for custom model training and Amazon Bedrock for foundation-model access power generative AI and ML use cases.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Infrastructure as Code & DevOps$q$, $q$CloudFormation, the AWS CDK, and CodePipeline let teams define, version, and automate environments and deployment pipelines.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Monitoring & Observability$q$, $q$Amazon CloudWatch and X-Ray provide metrics, logging, alarms, and distributed tracing across an application stack.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Global Infrastructure$q$, $q$A worldwide network of Regions and Availability Zones enables redundancy, low-latency deployment, and disaster recovery.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Container Orchestration$q$, $q$Amazon ECS, EKS, and Fargate support Docker and Kubernetes workloads with or without managing underlying servers.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Unmatched breadth of services (200+) covering nearly every infrastructure need in one ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Largest global infrastructure footprint of any cloud provider, enabling low-latency deployments worldwide$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Pay-as-you-go pricing with a free tier lowers the barrier to getting started$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Mature ecosystem of documentation, certifications, training, and a large partner and marketplace network$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Enterprise-grade security and compliance certifications suited to regulated industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Steep learning curve given the sheer number of services and configuration options$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Complex, granular pricing can lead to unexpectedly high bills without active cost management$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Meaningful support response times require paying for Developer, Business, or Enterprise support plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Management Console can feel overwhelming and dense compared to more streamlined platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Deep reliance on AWS-specific services and APIs creates vendor lock-in risk over time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$What is AWS used for?$q$, $q$AWS is used to host websites and applications, run backend infrastructure, store and manage data, build and train machine learning models, and support enterprise IT operations without owning physical servers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Does AWS have a free tier?$q$, $q$Yes, AWS offers a Free Tier with limited usage of many services at no cost, aimed at helping new customers experiment before scaling to paid, usage-based billing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Is AWS good for beginners or small businesses?$q$, $q$AWS can serve small businesses, but its breadth of services and configuration options create a learning curve; simpler platform-as-a-service tools may be a better fit for teams that don't want to manage infrastructure directly.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$How is AWS different from Microsoft Azure or Google Cloud?$q$, $q$AWS, Azure, and Google Cloud all offer comparable core infrastructure services; AWS is generally recognized for having the largest service catalog and global infrastructure footprint, while Azure and Google Cloud differentiate on Microsoft and Google ecosystem integration, respectively.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Does AWS support compliance requirements like HIPAA or GDPR?$q$, $q$Yes, AWS maintains a range of compliance certifications and offers services and documentation to help customers build HIPAA-, GDPR-, and SOC-compliant architectures, though compliance responsibility is shared between AWS and the customer.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Website & Application Hosting$q$, $q$Deploy and scale web applications using EC2, Lambda, or container services without managing physical hardware.$q$, $q$Startups and small-to-midsize businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Enterprise Data Center Migration$q$, $q$Move legacy on-premises workloads to the cloud, run hybrid environments, and modernize infrastructure incrementally.$q$, $q$Enterprise IT and infrastructure teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Big Data Analytics & Machine Learning$q$, $q$Process large datasets and train machine learning models using AWS's data and AI services at scale.$q$, $q$Data engineering and data science teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Serverless Application Development$q$, $q$Build event-driven applications with Lambda and managed services, minimizing server management overhead.$q$, $q$Software developers and DevOps engineers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Basic Support$q$, $q$Free$q$, NULL, $q$["24/7 access to customer service and documentation","AWS Trusted Advisor core checks","AWS Personal Health Dashboard access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Developer Support$q$, $q$Starting at $29/month$q$, $q$monthly$q$, $q$["Business-hours email support","General architectural guidance","One primary contact"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Business Support$q$, $q$Starting at $100/month$q$, $q$monthly$q$, $q$["24/7 phone, chat, and email support","Faster response times for production issues","Full set of Trusted Advisor checks"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$Enterprise Support$q$, $q$Starting at $15,000/month$q$, $q$monthly$q$, $q$["Dedicated Technical Account Manager (TAM)","Fastest response times for business-critical issues","Proactive guidance and operational reviews"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Amazon Web Services (AWS) is the cloud computing platform operated by Amazon.com, providing on-demand infrastructure and software services over the internet. Launched in 2006, AWS pioneered the modern utility computing model, letting organizations rent compute power, storage, and databases instead of buying and maintaining physical servers. It has since grown into the world's most widely adopted cloud provider, with a portfolio spanning more than 200 services across compute, storage, databases, networking, analytics, machine learning, security, and application integration.$q$, $q$At its core, AWS's foundational services include Amazon EC2 for virtual servers, AWS Lambda for serverless code execution, Amazon RDS and DynamoDB for managed databases, and Amazon VPC for private networking — with Amazon S3 object storage (covered separately on this site) rounding out the classic 'compute, storage, database' trio most workloads are built on. Everything runs on AWS's global network of Regions and Availability Zones, letting customers deploy close to their end users while maintaining redundancy and failover across independent data centers.$q$, $q$Access to this ecosystem comes through the AWS Management Console, a command-line interface, SDKs for major programming languages, and infrastructure-as-code tools like CloudFormation and the AWS CDK. A companion AWS Marketplace offers pre-configured software from third-party vendors, and usage-based billing means customers generally pay only for the resources they actually consume, with no upfront hardware investment required to get started.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$who-aws-is-for$q$, $q$Who AWS Is For$q$, 2, ARRAY[$q$AWS is built for organizations of virtually any size that need flexible, scalable infrastructure rather than a single packaged application. Startups use it to launch products without investing in physical servers, scaling compute and storage up or down as demand changes. Enterprises rely on AWS to migrate legacy data centers to the cloud, run hybrid environments, and modernize monolithic applications into microservices and containers.$q$, $q$Software development and DevOps teams turn to AWS for building serverless applications, CI/CD pipelines, and internal developer platforms, while data science and analytics teams use its machine learning and big-data services to train models and process large datasets at scale. Regulated industries — financial services, healthcare, and government — are also well served, thanks to AWS's compliance certifications and dedicated offerings like AWS GovCloud for government workloads.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$AWS is not the easiest entry point for individuals, solo developers, or very small teams who simply want to deploy a website or app without managing infrastructure decisions. The sheer number of overlapping services, configuration options, and security settings creates a steep learning curve; teams that want a simpler, more opinionated platform-as-a-service experience are often better served by tools like Vercel, Netlify, Heroku, or Render, which trade some flexibility for far less operational overhead.$q$, $q$Cost-sensitive projects and hobbyists should also be cautious: AWS's usage-based pricing can produce unpredictable bills if resources aren't actively monitored and governed, and unused or misconfigured services are a common source of billing surprises. Organizations unwilling to invest time in cost management, IAM security configuration, or ongoing training may find themselves paying for complexity they don't fully use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$AWS's compute layer covers nearly every deployment model: Amazon EC2 offers configurable virtual machines across dozens of instance families, AWS Lambda runs code in response to events without server management, and Amazon ECS, EKS, and Fargate provide container orchestration for teams standardizing on Docker or Kubernetes. Auto Scaling and Elastic Load Balancing keep these workloads resilient under variable traffic, adding or removing capacity automatically.$q$, $q$Beyond compute, AWS provides managed database services — Amazon RDS, Aurora, and DynamoDB — that handle patching, backups, and replication, alongside networking and security tools like Amazon VPC, Route 53 for DNS, CloudFront for content delivery, and AWS Identity and Access Management (IAM) for fine-grained permissions. Amazon CloudWatch and X-Ray add monitoring, logging, and distributed tracing across an entire application stack, giving teams visibility into performance and cost.$q$, $q$For teams building with AI, Amazon SageMaker supports custom model training and deployment, while Amazon Bedrock provides access to foundation models for generative AI use cases. Infrastructure-as-code tooling — CloudFormation, the AWS CDK, and CodePipeline — lets teams define and automate environments, and AWS Organizations, Control Tower, and Cost Explorer help larger enterprises govern multi-account environments and control spend across business units.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37230cac-8680-4f59-8fa6-d34a5321ea4d', $q$the-aws-experience$q$, $q$The AWS Experience$q$, 2, ARRAY[$q$Using AWS day to day means working primarily through the AWS Management Console, a dense but powerful web interface that surfaces the full breadth of the platform's services, or through the CLI and SDKs for teams that prefer infrastructure as code. New users typically face a real learning curve — AWS's documentation is extensive, and the company backs it with structured training through AWS Skill Builder and a well-recognized certification program covering everything from cloud practitioner basics to specialty architecture exams.$q$, $q$Support is tiered: a free Basic plan covers account and billing help, while paid Developer, Business, and Enterprise plans add faster response times, architectural guidance, and eventually a dedicated Technical Account Manager. AWS also maintains an active community presence through its annual re:Invent conference, regional user groups, and a large partner network of consultants and independent software vendors building on top of the platform.$q$, $q$Overall, AWS delivers unmatched breadth and global reliability, but that power comes with real complexity — teams that invest in learning its services and actively governing costs tend to get the most value, while those wanting a simpler, more guided experience may prefer a narrower, more opinionated platform instead.$q$]::text[], 4);
