-- ── Around ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Around was a floating-bubble video calling app that cut meeting fatigue for remote teams; Miro acquired it in 2022 and sunset it in 2025.$q$,
  pricing_model = $q$Freemium$q$,
  starting_price = $q$Free$q$,
  founded_year = 2018,
  company_size = $q$~35 employees (at the time of Miro's 2022 acquisition)$q$,
  headquarters = $q$Redwood City, California, US$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Around's floating-bubble video calls once fought meeting fatigue for remote teams — see its features, pricing history, and why Miro discontinued it in 2025.$q$,
  og_description = $q$Around's floating-bubble video calls once fought meeting fatigue for remote teams — see its features, pricing history, and why Miro discontinued it in 2025.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eb2d22a1-1ce3-4203-a28c-4dcd411456cf';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'eb2d22a1-1ce3-4203-a28c-4dcd411456cf' AND logo IS NULL AND website IS NOT NULL;









